var e=JSON.parse(`[{"id":"L3_1","type":"dialog","speaker":"SOLDIER_ADMIN_WHITE_NULL","text":{"KOREA":"이게 무슨……?","JPN":"これはいったい……？","ENG":"What...?","TWN":"這是什麼……？"},"stage":{"bg":"CORRIDOR_04","slots":{"L":null,"C":{"char_id":"SOLDIER_ADMIN_WHITE_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"SOLDIER_ADMIN_WHITE_NULL","text":{"KOREA":"불과 몇 시간 전에 여기서 대체 무슨 일이 벌어진 거지?","JPN":"たった数時間で、いったいここで何があったんだ？","ENG":"What on earth happened here a few hours ago?","TWN":"幾個小時前，這裡究竟發生了什麼！？"},"stage":{"bg":"CORRIDOR_04","slots":{"L":null,"C":{"char_id":"SOLDIER_ADMIN_WHITE_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"SOLDIER_ADMIN_WHITE_NULL","text":{"KOREA":"무슨 차원 폭풍이라도 휩쓸고 지나간 것 같은데…….","JPN":"次元の暴風でもあったかのような有様だ……","ENG":"It looks like a dimensional storm passed by here...","TWN":"就像是被次元風暴襲擊過一樣……"},"stage":{"bg":"CORRIDOR_04","slots":{"L":null,"C":{"char_id":"SOLDIER_ADMIN_WHITE_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"SHIRASAKI_SWANSONG_NPC_NULL","text":{"KOREA":"당신들! 대체 이 사태를 어떻게 책임질 거요!","JPN":"あなたたち！　この事態についてどう責任をとってくれるんですか！","ENG":"Hey! How are you all going to take responsibility for what happened here?!","TWN":"你們！到底打算怎麼負責這場災難！"},"stage":{"bg":"CORRIDOR_04","slots":{"L":null,"C":{"char_id":"SHIRASAKI_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"SHIRASAKI_SWANSONG_NPC_NULL","text":{"KOREA":"동력실이 파괴되어 4 구역 승강기 전체를 운영할 수 없게 되었소!","JPN":"動力室が破壊されて、4区域の昇降機すべてが運行できなくなった！","ENG":"The power room is destroyed, rendering all the elevators in Zone 4 inoperable!","TWN":"動力室被破壞，4區的所有升降梯都無法運行了！"},"stage":{"bg":"CORRIDOR_04","slots":{"L":null,"C":{"char_id":"SHIRASAKI_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"SOLDIER_ADMIN_WHITE_NULL","text":{"KOREA":"진정하세요.","JPN":"落ち着いてください。","ENG":"Calm down.","TWN":"請冷靜。"},"stage":{"bg":"CORRIDOR_04","slots":{"L":null,"C":{"char_id":"SOLDIER_ADMIN_WHITE_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"SOLDIER_ADMIN_WHITE_NULL","text":{"KOREA":"지금 챔버 관리국도 사태 규명을 위해, 최선을 다하고 있습니다.","JPN":"今チェンバー管理局も、真相究明のために尽力しています。","ENG":"Chamber City Management is doing its best to clarify the situation.","TWN":"現在強巴的管理局也在盡全力查明事態。"},"stage":{"bg":"CORRIDOR_04","slots":{"L":null,"C":{"char_id":"SOLDIER_ADMIN_WHITE_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"SHIRASAKI_SWANSONG_NPC_NULL","text":{"KOREA":"진정? 지금 진정이라고 했소?","JPN":"落ち着く？　落ち着いてなんかいられるか！","ENG":"Calm down? Did you just tell me to calm down?","TWN":"冷靜？你剛才說冷靜？"},"stage":{"bg":"CORRIDOR_04","slots":{"L":{"char_id":"SOLDIER_ADMIN_WHITE_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SHIRASAKI_SWANSONG_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"SHIRASAKI_SWANSONG_NPC_NULL","text":{"KOREA":"우리는 챔버 관리국과 공식 협약을 맺은 리프트 코퍼레이션이오!","JPN":"私たちはチェンバー管理局と公式条約を結んだリフト・コーポレーションです！","ENG":"We are a lift company that has an official partnership with Chamber City Management!","TWN":"我們是與強巴管理局簽訂正式協定的起重公司！"},"stage":{"bg":"CORRIDOR_04","slots":{"L":{"char_id":"SOLDIER_ADMIN_WHITE_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SHIRASAKI_SWANSONG_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"SHIRASAKI_SWANSONG_NPC_NULL","text":{"KOREA":"고작 테러리스트 하나 때문에 이런 사태가 생기는 게 지금 말이 된다고 생각하오?","JPN":"テロリスト一人のせいでこんな事態が起きるなんて、あり得るんですか！","ENG":"Are you telling me to believe that a single terrorist caused all this commotion?","TWN":"僅僅因為一個恐怖分子就引發這樣的災難，這可說不通喔？"},"stage":{"bg":"CORRIDOR_04","slots":{"L":{"char_id":"SOLDIER_ADMIN_WHITE_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SHIRASAKI_SWANSONG_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"SHIRASAKI_SWANSONG_NPC_NULL","text":{"KOREA":"우리 회사가 매년 관리국에 승강기 수익의 몇 퍼센트를 지불하는 줄 아시오?","JPN":"うちの会社が毎年昇降機から得る収益の何パーセントを管理局に払っているのかわかります！？","ENG":"Do you even know what percentage of our elevator revenue the Administration takes from us each year?","TWN":"你知道我們公司每年要向管理局支付多少升降機收入的抽成嗎！？"},"stage":{"bg":"CORRIDOR_04","slots":{"L":{"char_id":"SOLDIER_ADMIN_WHITE_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SHIRASAKI_SWANSONG_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"SOLDIER_ADMIN_WHITE_NULL","text":{"KOREA":"그러니까 관리국도 최선을 다해서…….","JPN":"ですから管理局も最善を尽くして……","ENG":"As I said, the City Management is doing its best–","TWN":"所以管理局也在盡全力……"},"stage":{"bg":"CORRIDOR_04","slots":{"L":{"char_id":"SOLDIER_ADMIN_WHITE_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SHIRASAKI_SWANSONG_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"OPR_ADMIN_WHITE_NULL","text":{"KOREA":"대응팀, 들리나요?","JPN":"対応チーム、聞こえていますか？","ENG":"Response team, do you copy?","TWN":"應對小組，聽得到嗎？"},"stage":{"bg":"CORRIDOR_04","slots":{"L":null,"C":{"char_id":"OPR_ADMIN_WHITE_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"OPR_ADMIN_WHITE_NULL","text":{"KOREA":"단서를 찾았습니다. 지금 즉시 본부로 귀환하세요.","JPN":"手がかりが見つかりました。直ちに本部へ帰還してください。","ENG":"We found a lead. Return to HQ immediately.","TWN":"找到了線索。請立即返回總部。"},"stage":{"bg":"CORRIDOR_04","slots":{"L":null,"C":{"char_id":"OPR_ADMIN_WHITE_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"SOLDIER_ADMIN_WHITE_NULL","text":{"KOREA":"네? 단서를 찾았는데 본부로 귀환하라니요?","JPN":"え？　手がかりが見つかったのに本部へ帰還？","ENG":"What? Return to HQ when you found a lead?","TWN":"什麼？為什麼找到了線索卻要返回總部？"},"stage":{"bg":"CORRIDOR_04","slots":{"L":null,"C":{"char_id":"SOLDIER_ADMIN_WHITE_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"OPR_ADMIN_WHITE_NULL","text":{"KOREA":"현장에서 <color=#ffd34c>메시지</color>가 발견되었습니다.","JPN":"現場で<color=#ffd34c>メッセージ</color>が見つかりました。","ENG":"A <color=#ffd34c>message</color> was found at the scene.","TWN":"現場發現了一張<color=#ffd34c>紙片</color>。"},"stage":{"bg":"CORRIDOR_04","slots":{"L":null,"C":{"char_id":"OPR_ADMIN_WHITE_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"OPR_ADMIN_WHITE_NULL","text":{"KOREA":"관리국이 수년간 쫓고 있는 국제적인 테러 단체의 수법으로 추정됩니다.","JPN":"管理局がここ数年間追跡している、国際的テロ集団の仕業だと思われます。","ENG":"We believe it to be the method of an international terrorist group that the Administration has been pursuing for several years.","TWN":"推測是管理局追捕多年的國際恐怖組織的手法。"},"stage":{"bg":"CORRIDOR_04","slots":{"L":null,"C":{"char_id":"OPR_ADMIN_WHITE_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"OPR_ADMIN_WHITE_NULL","text":{"KOREA":"따라서 현시간부로 이 사건은 관리국 대테러 수사팀으로 이관됩니다.","JPN":"現時刻を持ってこの事件は管理局の耐テロ捜査チームに移管します。","ENG":"So, the Administration's Counterterrorism Investigation team will take on the case from here.","TWN":"因此，從現在起該案件將移交給管理局反恐調查組處理。"},"stage":{"bg":"CORRIDOR_04","slots":{"L":null,"C":{"char_id":"OPR_ADMIN_WHITE_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"OPR_ADMIN_WHITE_NULL","text":{"KOREA":"그러니 대응팀 전원 복귀하도록 하세요.","JPN":"対応チームは全員帰還してください。","ENG":"So, the response team is ordered to return to HQ.","TWN":"所有應對小組成員請即刻返回。"},"stage":{"bg":"CORRIDOR_04","slots":{"L":null,"C":{"char_id":"OPR_ADMIN_WHITE_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"subtitle","speaker":null,"text":{"KOREA":"같은 시간","JPN":"同時刻","ENG":"Meanwhile","TWN":"同一時間","SCN":"同一时间","DEU":"Meanwhile","FRA":"Meanwhile"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L34_1","type":"subtitle","speaker":null,"text":{"KOREA":"관리국 직할 도시 <color=#ffd34c>샤레이드</color>","JPN":"管理局直轄都市<color=#ffd34c>シャレード</color>","ENG":"Administration Direct Control City, <color=#ffd34c>Charade</color>","TWN":"管理局直轄市<color=#ffd34c>查雷德</color>","SCN":"管理局直辖城市<color=#ffd34c>查雷德</color>","DEU":"Administration Direct Control City, <color=#ffd34c>Charade</color>","FRA":"Administration Direct Control City, <color=#ffd34c>Charade</color>"},"stage":{"bg":"CHARADE","slots":{"L":null,"C":null,"R":null}}},{"id":"L38_1","type":"dialog","speaker":"STAFF_CANARY_NULL_NULL","text":{"KOREA":"아, 네. 카나리아 스쿼드의 스키너입니다.","JPN":"あ、はい。カナリア・スクワッドのスキナーです。","ENG":"Hello? Yes, this is Skinner of the Canary Squad.","TWN":"是，你好，我是金絲雀小隊的史金納。"},"stage":{"bg":"CITY_CENTER2","slots":{"L":null,"C":{"char_id":"STAFF_CANARY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"STAFF_CANARY_NULL_NULL","text":{"KOREA":"네? 지금 누구시라고…….","JPN":"はい？　今、どちら様と……？","ENG":"Excuse me? Who is this again...?","TWN":"嗯？你說你找誰……"},"stage":{"bg":"CITY_CENTER2","slots":{"L":null,"C":{"char_id":"STAFF_CANARY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"STAFF_CANARY_NULL_NULL","text":{"KOREA":"……잠시만요. 금방 바꿔 드리겠습니다.","JPN":"……少々お待ちください。すぐにお繋ぎします。","ENG":"...Please hold. I'll get him for you.","TWN":"……請稍等，我馬上把電話轉給他。"},"stage":{"bg":"CITY_CENTER2","slots":{"L":null,"C":{"char_id":"STAFF_CANARY_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}}]`);export{e as default};